#!/usr/bin/env python3
"""
MA Triple Strategy - MA20/MA50 三线排列

价格 + 双均线三段排列：
- current > MA20 > MA50 → BUY（多头排列）
- current < MA20 < MA50 → SELL（空头排列）
- 其他 → HOLD
"""

from typing import Dict, List, Optional
from dataclasses import dataclass

from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class MATripleConfig:
    """ADX 2yi strategy configuration"""
    short_period: int = 20
    long_period: int = 50


class MATriple(Strategy):
    """ADX 2yi trading strategy（MA三段排列版）"""

    def __init__(self, exchange=None, config: Optional[MATripleConfig] = None):
        self.exchange = exchange
        self.config = config or MATripleConfig()

    @property
    def name(self) -> str:
        return "matriple"

    def generate_signal(
        self, coin: str, klines: List[Dict] = None
    ) -> TradingSignal:
        min_required = self.config.long_period
        if not klines or len(klines) < min_required:
            return TradingSignal(
                signal=Signal.HOLD,
                confidence=0.0,
                coin=coin,
                timestamp=klines[-1]["time"] if klines else 0,
                metadata={"reason": "Insufficient klines"},
            )

        closes = [c["close"] for c in klines]
        current = closes[-1]

        ma_short = sum(closes[-self.config.short_period:]) / self.config.short_period
        ma_long = sum(closes[-self.config.long_period:]) / self.config.long_period

        if current > ma_short > ma_long:
            signal = Signal.BUY
            trend = "strong_uptrend"
        elif current < ma_short < ma_long:
            signal = Signal.SELL
            trend = "strong_downtrend"
        else:
            signal = Signal.HOLD
            trend = "consolidation"

        return TradingSignal(
            signal=signal,
            confidence=0.6,
            coin=coin,
            timestamp=klines[-1]["time"],
            metadata={
                "ma_short": ma_short,
                "ma_long": ma_long,
                "current": current,
                "trend": trend,
            },
        )

#!/usr/bin/env python3
"""
CMO Strategy — Chande Momentum Oscillator (Tushar Chande标准实现)

CMO = (sum_ups - sum_downs) / (sum_ups + sum_downs) × 100
只看最近 period 根K线的涨跌幅，不是全部历史。

Signal: zero-line crossover + slope confirmation
- CMO从负转正 → BUY
- CMO从正转负 → SELL
"""

from typing import Dict, List, Optional
from dataclasses import dataclass

from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class CMOConfig:
    """CMO configuration"""
    period: int = 9


class CMO(Strategy):
    """Chande Momentum Oscillator — 标准实现"""

    def __init__(self, exchange=None, config: Optional[CMOConfig] = None):
        self.exchange = exchange
        self.config = config or CMOConfig()

    @property
    def name(self) -> str:
        return "cmo"

    def _calc_cmo(self, prices: List[float], period: int) -> float:
        """CMO over the last `period` bars"""
        if len(prices) < period + 1:
            return 0.0

        ups = 0.0
        downs = 0.0
        for i in range(-period, 0):
            change = prices[i] - prices[i - 1]
            if change > 0:
                ups += change
            elif change < 0:
                downs += abs(change)

        total = ups + downs
        if total == 0:
            return 0.0
        return (ups - downs) / total * 100

    def generate_signal(
        self, coin: str, klines: List[Dict] = None
    ) -> TradingSignal:
        min_required = self.config.period + 2
        if not klines or len(klines) < min_required:
            return TradingSignal(
                signal=Signal.HOLD,
                confidence=0.0,
                coin=coin,
                timestamp=klines[-1]["time"] if klines else 0,
                metadata={"reason": "Insufficient klines"},
            )

        prices = [c["close"] for c in klines]
        cmo = self._calc_cmo(prices, self.config.period)
        prev_cmo = self._calc_cmo(prices[:-1], self.config.period)

        # Zero-line crossover
        if cmo > 0 and prev_cmo <= 0:
            signal = Signal.BUY
            trend = "bullish_cross"
        elif cmo < 0 and prev_cmo >= 0:
            signal = Signal.SELL
            trend = "bearish_cross"
        else:
            signal = Signal.HOLD
            trend = "no_cross"

        return TradingSignal(
            signal=signal,
            confidence=abs(cmo) / 100,
            coin=coin,
            timestamp=klines[-1]["time"],
            metadata={
                "cmo": cmo,
                "prev_cmo": prev_cmo,
                "trend": trend,
            },
        )

#!/usr/bin/env python3
"""
Momentum Slope Strategy

Momentum direction + slope strength.
Originally mislabeled as CMO — actual logic is slope-based, not Chande's formula.

if/if chain fixed to proper if/elif.
"""

from typing import Dict, List, Optional
from dataclasses import dataclass

from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class MomentumSlopeConfig:
    short_period: int = 9
    long_period: int = 20


class MomentumSlope(Strategy):
    """Momentum slope trading strategy"""

    def __init__(self, exchange=None, config: Optional[MomentumSlopeConfig] = None):
        self.exchange = exchange
        self.config = config or MomentumSlopeConfig()

    @property
    def name(self) -> str:
        return "momentum_slope"

    def _momentum(self, prices: List[float]) -> float:
        """Sum of ups minus downs over all prices (raw momentum)"""
        ups = 0.0
        downs = 0.0
        for i in range(1, len(prices)):
            change = prices[i] - prices[i - 1]
            if change > 0:
                ups += change
            elif change < 0:
                downs += abs(change)
        total = ups + downs
        if total == 0:
            return 0.0
        return (ups - downs) / total * 100

    def generate_signal(
        self, coin: str, klines: List[Dict] = None
    ) -> TradingSignal:
        min_required = 30
        if not klines or len(klines) < min_required:
            return TradingSignal(
                signal=Signal.HOLD,
                confidence=0.0,
                coin=coin,
                timestamp=klines[-1]["time"] if klines else 0,
                metadata={"reason": "Insufficient klines"},
            )

        prices = [c["close"] for c in klines]
        mom = self._momentum(prices)
        prev_mom = self._momentum(prices[:-1])

        # Fixed if/elif chain (original had if/if/if-elif-else overwrite bug)
        if prev_mom <= 0 and mom > 0:
            signal = Signal.BUY
            trend = "momentum_up"
        elif prev_mom >= 0 and mom < 0:
            signal = Signal.SELL
            trend = "momentum_down"
        elif mom > prev_mom and mom > 10:
            signal = Signal.BUY
            trend = "strengthening"
        elif mom < prev_mom and mom < -10:
            signal = Signal.SELL
            trend = "weakening"
        else:
            signal = Signal.HOLD
            trend = "neutral"

        return TradingSignal(
            signal=signal,
            confidence=abs(mom) / 100,
            coin=coin,
            timestamp=klines[-1]["time"],
            metadata={
                "momentum": mom,
                "prev_momentum": prev_mom,
                "trend": trend,
            },
        )

"""Ehlers Instantaneous Trendline — Hilbert变换趋势线"""
import math
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class EhlersITLConfig:
    alpha: float = 0.07


class EhlersITL(Strategy):
    def __init__(self, exchange=None, config: Optional[EhlersITLConfig] = None):
        self.exchange = exchange
        self.config = config or EhlersITLConfig()

    @property
    def name(self) -> str:
        return "ehlers_itl"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        if not klines or len(klines) < 12:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        prices = [(c["high"] + c["low"]) / 2 for c in klines]
        itl = self._calc_itl(prices)

        if len(itl) < 5:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"])

        current = itl[-1]
        lag = itl[-3]
        prev_current = itl[-2]
        prev_lag = itl[-4]

        if current > lag and prev_current <= prev_lag:
            signal = Signal.BUY
        elif current < lag and prev_current >= prev_lag:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=0.7,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"itl": current, "itl_lag": lag})

    def _calc_itl(self, prices):
        a = self.config.alpha
        n = len(prices)
        itl = [0.0] * n

        for i in range(n):
            if i < 7:
                itl[i] = prices[i]
            else:
                itl[i] = (a - a * a / 4) * prices[i] + \
                         0.5 * a * a * prices[i - 1] - \
                         (a - 0.75 * a * a) * prices[i - 2] + \
                         2 * (1 - a) * itl[i - 1] - \
                         (1 - a) ** 2 * itl[i - 2]
        return itl

"""Mass Index — 反转鼓包检测（>27回落<26.5 = 趋势反转）"""
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class MassIndexConfig:
    ema_period: int = 9
    sum_period: int = 25
    bulge_trigger: float = 27.0
    bulge_release: float = 26.5


class MassIndex(Strategy):
    def __init__(self, exchange=None, config: Optional[MassIndexConfig] = None):
        self.exchange = exchange
        self.config = config or MassIndexConfig()

    @property
    def name(self) -> str:
        return "mass_index"

    def _ema_series(self, values, period):
        if len(values) < period:
            return list(values)
        k = 2 / (period + 1)
        ema = sum(values[:period]) / period
        result = [ema]
        for v in values[period:]:
            ema = v * k + ema * (1 - k)
            result.append(ema)
        return result

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        need = self.config.ema_period * 2 + self.config.sum_period + 2
        if not klines or len(klines) < need:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        hl_range = [c["high"] - c["low"] for c in klines]
        ema1 = self._ema_series(hl_range, self.config.ema_period)
        ema2 = self._ema_series(ema1, self.config.ema_period)

        if len(ema2) < self.config.sum_period + 1:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"])

        ratios = []
        min_len = min(len(ema1), len(ema2))
        offset = len(ema1) - min_len
        for i in range(min_len):
            e2 = ema2[i]
            e1 = ema1[i + offset]
            ratios.append(e1 / e2 if e2 != 0 else 1.0)

        if len(ratios) < self.config.sum_period + 1:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"])

        mi = sum(ratios[-self.config.sum_period:])
        prev_mi = sum(ratios[-(self.config.sum_period + 1):-1])

        closes = [c["close"] for c in klines]
        ema9 = self._ema_series(closes, self.config.ema_period)
        trend_up = ema9[-1] > ema9[-2] if len(ema9) >= 2 else True

        bulge_now = mi < self.config.bulge_release
        bulge_prev = prev_mi >= self.config.bulge_trigger

        if bulge_now and bulge_prev:
            signal = Signal.BUY if not trend_up else Signal.SELL
        elif prev_mi < self.config.bulge_release and mi >= self.config.bulge_trigger:
            signal = Signal.HOLD
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=min(abs(mi - 25) / 5, 1.0),
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"mass_index": mi, "prev_mi": prev_mi, "trend_up": trend_up})
